CREATE OR REPLACE FUNCTION asset_ut.test_classify()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id     UUID;
  v_result JSONB;
  v_asset  RECORD;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Setup: insert unclassified asset
  INSERT INTO asset.asset (path, filename, mime_type)
  VALUES ('uploads/test.jpg', 'test.jpg', 'image/jpeg')
  RETURNING id INTO v_id;

  -- Verify initial state
  SELECT * INTO v_asset FROM asset.asset WHERE id = v_id;
  RETURN NEXT ok(v_asset.status = 'to_classify', 'initial status is to_classify');
  RETURN NEXT ok(v_asset.classified_at IS NULL, 'classified_at is null initially');

  -- Classify
  v_result := asset.classify(
    p_id          := v_id,
    p_title       := 'Concert jazz en plein air',
    p_description := 'Photo d''un concert de jazz dans un parc municipal',
    p_tags        := ARRAY['jazz', 'concert', 'musique', 'plein air'],
    p_width       := 1920,
    p_height      := 1080,
    p_orientation := 'paysage',
    p_saison      := 'été',
    p_credit      := 'Photo Studio',
    p_usage_hint  := 'bannière web',
    p_colors      := ARRAY['#1a2b3c', '#d4e5f6']
  );

  RETURN NEXT ok(v_result->>'status' = 'classified', 'classify returns classified status');

  -- Verify updated state
  SELECT * INTO v_asset FROM asset.asset WHERE id = v_id;
  RETURN NEXT ok(v_asset.status = 'classified', 'status updated to classified');
  RETURN NEXT ok(v_asset.classified_at IS NOT NULL, 'classified_at is set');
  RETURN NEXT ok(v_asset.title = 'Concert jazz en plein air', 'title is set');
  RETURN NEXT ok(cardinality(v_asset.tags) = 4, 'tags array has 4 elements');
  RETURN NEXT ok(v_asset.width = 1920, 'width is set');
  RETURN NEXT ok(v_asset.orientation = 'paysage', 'orientation is set');
  RETURN NEXT ok(v_asset.usage_hint = 'bannière web', 'usage_hint is set');

  -- Cleanup
  DELETE FROM asset.asset WHERE id = v_id;
END;
$function$;
COMMENT ON FUNCTION asset_ut.test_classify() IS 'Test classify: insert asset to_classify, classify it, verify status + classified_at';

CREATE OR REPLACE FUNCTION asset_ut.test_data_assets()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id1    UUID;
  v_id2    UUID;
  v_result JSONB;
  v_row    JSONB;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Setup
  INSERT INTO asset.asset (path, filename, mime_type, title, status)
  VALUES ('uploads/d1.jpg', 'd1.jpg', 'image/jpeg', 'Photo test 1', 'classified')
  RETURNING id INTO v_id1;

  INSERT INTO asset.asset (path, filename, mime_type, status)
  VALUES ('uploads/d2.jpg', 'd2.jpg', 'image/jpeg', 'to_classify')
  RETURNING id INTO v_id2;

  -- Test: format
  v_result := asset.data_assets('{}');
  RETURN NEXT ok(v_result ? 'rows', 'result has rows key');
  RETURN NEXT ok(v_result ? 'has_more', 'result has has_more key');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 2, 'at least 2 rows returned');

  -- Test: row is array of 7 elements (id, filename, title, mime, status, tags, created)
  v_row := (v_result->'rows')->0;
  RETURN NEXT ok(jsonb_array_length(v_row) = 7, 'each row has 7 columns');

  -- Test: status filter
  v_result := asset.data_assets('{"p_status":"classified"}');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 1, 'status filter works');

  -- Test: pagination
  v_result := asset.data_assets('{"_size":1}');
  RETURN NEXT ok((v_result->>'has_more')::boolean, 'has_more true with size=1');

  v_result := asset.data_assets('{"_size":1,"_offset":1}');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 1, 'offset pagination works');

  -- Cleanup
  DELETE FROM asset.asset WHERE id IN (v_id1, v_id2);
END;
$function$;
COMMENT ON FUNCTION asset_ut.test_data_assets() IS 'Test data_assets: verify cursor format (rows array, has_more boolean)';

CREATE OR REPLACE FUNCTION asset_ut.test_search()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id1    UUID;
  v_id2    UUID;
  v_id3    UUID;
  v_result JSONB;
  v_count  INT;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Setup: 3 assets
  INSERT INTO asset.asset (path, filename, mime_type, status, title, description, tags)
  VALUES ('uploads/a.jpg', 'a.jpg', 'image/jpeg', 'classified', 'Concert de jazz', 'Un concert en plein air', ARRAY['jazz','musique'])
  RETURNING id INTO v_id1;

  INSERT INTO asset.asset (path, filename, mime_type, status, title, description, tags)
  VALUES ('uploads/b.png', 'b.png', 'image/png', 'to_classify', NULL, NULL, '{}')
  RETURNING id INTO v_id2;

  INSERT INTO asset.asset (path, filename, mime_type, status, title, description, tags)
  VALUES ('uploads/c.jpg', 'c.jpg', 'image/jpeg', 'classified', 'Marché de Noël', 'Stand de vin chaud', ARRAY['marché','hiver'])
  RETURNING id INTO v_id3;

  -- Test: all assets
  v_result := asset.search('{}');
  v_count := jsonb_array_length(v_result->'rows');
  RETURN NEXT ok(v_count >= 3, 'search returns at least 3 assets');

  -- Test: status filter
  v_result := asset.search('{"p_status":"to_classify"}');
  v_count := jsonb_array_length(v_result->'rows');
  RETURN NEXT ok(v_count >= 1, 'status filter returns to_classify assets');

  -- Test: FTS
  v_result := asset.search('{"q":"jazz"}');
  v_count := jsonb_array_length(v_result->'rows');
  RETURN NEXT ok(v_count >= 1, 'FTS finds jazz');

  -- Test: tags overlap
  v_result := asset.search('{"p_tags":["hiver"]}');
  v_count := jsonb_array_length(v_result->'rows');
  RETURN NEXT ok(v_count >= 1, 'tags filter finds hiver');

  -- Test: mime filter
  v_result := asset.search('{"p_mime":"image/png"}');
  v_count := jsonb_array_length(v_result->'rows');
  RETURN NEXT ok(v_count >= 1, 'mime filter finds png');

  -- Test: has_more pagination
  v_result := asset.search('{"_size":1}');
  RETURN NEXT ok((v_result->>'has_more')::boolean, 'has_more is true with size=1');

  -- Cleanup
  DELETE FROM asset.asset WHERE id IN (v_id1, v_id2, v_id3);
END;
$function$;
COMMENT ON FUNCTION asset_ut.test_search() IS 'Test search: insert multiple assets, test FTS, status filter, tags filter';

